    {
        return BOOT_FLAGS0 & 1u;
    }

    /**
     * Get BOOT_FLAGS0's ENABLE_BOOTSEL_LED bit.
     *
     * Enable bootloader activity LED. If set, bootsel_led_cfg is assumed to be
     * valid
     */
    inline bool get_BOOT_FLAGS0_ENABLE_BOOTSEL_LED() volatile
    {
        return BOOT_FLAGS0 & (1u << 1u);
    }

    /**
     * Get BOOT_FLAGS0's ENABLE_BOOTSEL_NON_DEFAULT_PLL_XOSC_CFG bit.
     *
     * Enable loading of the non-default XOSC and PLL configuration before
     * entering BOOTSEL mode.
     *
     *                             Ensure that BOOTSEL_XOSC_CFG and
     * BOOTSEL_PLL_CFG are correctly programmed before setting this bit.
     *
     *                             If this bit is set, user software may use
     * the contents of BOOTSEL_PLL_CFG to calculated the expected XOSC
     * frequency based on the fixed USB boot frequency of 48 MHz.
     */
    inline bool
    get_BOOT_FLAGS0_ENABLE_BOOTSEL_NON_DEFAULT_PLL_XOSC_CFG() volatile
    {
        return BOOT_FLAGS0 & (1u << 2u);
    }

    /**
     * Get BOOT_FLAGS0's FLASH_IO_VOLTAGE_1V8 bit.
     *
     * If 1, configure the QSPI pads for 1.8 V operation when accessing flash
     * for the first time from the bootrom, using the VOLTAGE_SELECT register
     * for the QSPI pads bank. This slightly improves the input timing of the
     * pads at low voltages, but does not affect their output characteristics.
     *
     *                             If 0, leave VOLTAGE_SELECT in its reset
     * state (suitable for operation at and above 2.5 V)
     */
    inline bool get_BOOT_FLAGS0_FLASH_IO_VOLTAGE_1V8() volatile
    {
        return BOOT_FLAGS0 & (1u << 3u);
    }

    /**
     * Get BOOT_FLAGS0's FAST_SIGCHECK_ROSC_DIV bit.
     *
     * Enable quartering of ROSC divisor during signature check, to reduce
     * secure boot time
     */
    inline bool get_BOOT_FLAGS0_FAST_SIGCHECK_ROSC_DIV() volatile
    {
        return BOOT_FLAGS0 & (1u << 4u);
    }

    /**
     * Get BOOT_FLAGS0's FLASH_DEVINFO_ENABLE bit.
     *
     * Mark FLASH_DEVINFO as containing valid, ECC'd data which describes
     * external flash devices.
     */
    inline bool get_BOOT_FLAGS0_FLASH_DEVINFO_ENABLE() volatile
    {
        return BOOT_FLAGS0 & (1u << 5u);
    }

    /**
     * Get BOOT_FLAGS0's OVERRIDE_FLASH_PARTITION_SLOT_SIZE bit.
     *
     * Override the limit for default flash metadata scanning.
     *
     *                             The value is specified in
     * FLASH_PARTITION_SLOT_SIZE. Make sure FLASH_PARTITION_SLOT_SIZE is valid
     * before setting this bit
     */
    inline bool get_BOOT_FLAGS0_OVERRIDE_FLASH_PARTITION_SLOT_SIZE() volatile
    {
        return BOOT_FLAGS0 & (1u << 6u);
    }

    /**
     * Get BOOT_FLAGS0's SINGLE_FLASH_BINARY bit.
     *
     * Restrict flash boot path to use of a single binary at the start of flash
     */
    inline bool get_BOOT_FLAGS0_SINGLE_FLASH_BINARY() volatile
    {
        return BOOT_FLAGS0 & (1u << 7u);
    }

