    /**
     * Get BOOT_FLAGS0's DISABLE_OTP_BOOT bit.
     *
     * Takes precedence over ENABLE_OTP_BOOT.
     */
    inline bool get_BOOT_FLAGS0_DISABLE_OTP_BOOT() volatile
    {
        return BOOT_FLAGS0 & (1u << 13u);
    }

    /**
     * Get BOOT_FLAGS0's ENABLE_OTP_BOOT bit.
     *
     * Enable OTP boot. A number of OTP rows specified by OTPBOOT_LEN will be
     * loaded, starting from OTPBOOT_SRC, into the SRAM location specified by
     * OTPBOOT_DST1 and OTPBOOT_DST0.
     *
     *                             The loaded program image is stored with ECC,
     * 16 bits per row, and must contain a valid IMAGE_DEF. Do not set this bit
     * without first programming an image into OTP and configuring OTPBOOT_LEN,
     * OTPBOOT_SRC, OTPBOOT_DST0 and OTPBOOT_DST1.
     *
     *                             Note that OTPBOOT_LEN and OTPBOOT_SRC must
     * be even numbers of OTP rows. Equivalently, the image must be a multiple
     * of 32 bits in size, and must start at a 32-bit-aligned address in the
     * ECC read data address window.
     */
    inline bool get_BOOT_FLAGS0_ENABLE_OTP_BOOT() volatile
    {
        return BOOT_FLAGS0 & (1u << 14u);
    }

