    /**
     * Get all of BOOT_FLAGS0's bit fields.
     *
     * (read-only) Disable/Enable boot paths/features in the RP2350 mask ROM.
     * Disables always supersede enables. Enables are provided where there are
     * other configurations in OTP that must be valid. (RBIT-3)
     */
    inline void get_BOOT_FLAGS0(
        bool &DISABLE_BOOTSEL_EXEC2, bool &ENABLE_BOOTSEL_LED,
        bool &ENABLE_BOOTSEL_NON_DEFAULT_PLL_XOSC_CFG,
        bool &FLASH_IO_VOLTAGE_1V8, bool &FAST_SIGCHECK_ROSC_DIV,
        bool &FLASH_DEVINFO_ENABLE, bool &OVERRIDE_FLASH_PARTITION_SLOT_SIZE,
        bool &SINGLE_FLASH_BINARY, bool &DISABLE_AUTO_SWITCH_ARCH,
        bool &SECURE_PARTITION_TABLE, bool &HASHED_PARTITION_TABLE,
        bool &ROLLBACK_REQUIRED, bool &DISABLE_FLASH_BOOT,
        bool &DISABLE_OTP_BOOT, bool &ENABLE_OTP_BOOT,
        bool &DISABLE_POWER_SCRATCH, bool &DISABLE_WATCHDOG_SCRATCH,
        bool &DISABLE_BOOTSEL_USB_MSD_IFC,
        bool &DISABLE_BOOTSEL_USB_PICOBOOT_IFC,
        bool &DISABLE_BOOTSEL_UART_BOOT,
        bool &DISABLE_XIP_ACCESS_ON_SRAM_ENTRY,
        bool &DISABLE_SRAM_WINDOW_BOOT) volatile
    {
        uint32_t curr = BOOT_FLAGS0;

        DISABLE_BOOTSEL_EXEC2 = curr & 1u;
        ENABLE_BOOTSEL_LED = curr & (1u << 1u);
        ENABLE_BOOTSEL_NON_DEFAULT_PLL_XOSC_CFG = curr & (1u << 2u);
        FLASH_IO_VOLTAGE_1V8 = curr & (1u << 3u);
        FAST_SIGCHECK_ROSC_DIV = curr & (1u << 4u);
        FLASH_DEVINFO_ENABLE = curr & (1u << 5u);
        OVERRIDE_FLASH_PARTITION_SLOT_SIZE = curr & (1u << 6u);
        SINGLE_FLASH_BINARY = curr & (1u << 7u);
        DISABLE_AUTO_SWITCH_ARCH = curr & (1u << 8u);
        SECURE_PARTITION_TABLE = curr & (1u << 9u);
        HASHED_PARTITION_TABLE = curr & (1u << 10u);
        ROLLBACK_REQUIRED = curr & (1u << 11u);
        DISABLE_FLASH_BOOT = curr & (1u << 12u);
        DISABLE_OTP_BOOT = curr & (1u << 13u);
        ENABLE_OTP_BOOT = curr & (1u << 14u);
        DISABLE_POWER_SCRATCH = curr & (1u << 15u);
        DISABLE_WATCHDOG_SCRATCH = curr & (1u << 16u);
        DISABLE_BOOTSEL_USB_MSD_IFC = curr & (1u << 17u);
        DISABLE_BOOTSEL_USB_PICOBOOT_IFC = curr & (1u << 18u);
        DISABLE_BOOTSEL_UART_BOOT = curr & (1u << 19u);
        DISABLE_XIP_ACCESS_ON_SRAM_ENTRY = curr & (1u << 20u);
        DISABLE_SRAM_WINDOW_BOOT = curr & (1u << 21u);
    }

