    /**
     * Get FLASH_DEVINFO's CS1_GPIO field.
     *
     * Indicate a GPIO number to be used for the secondary flash chip select
     * (CS1), which selects the external QSPI device mapped at system addresses
     * 0x11000000 through 0x11ffffff. There is no such configuration for CS0,
     * as the primary chip select has a dedicated pin.
     *
     *                             On RP2350 the permissible GPIO numbers are
     * 0, 8, 19 and 47.
     *
     *                             Ignored if CS1_size is zero. If CS1_SIZE is
     * nonzero, the bootrom will automatically configure this GPIO as a second
     * chip select upon entering the flash boot path, or entering any other
     * path that may use the QSPI flash interface, such as BOOTSEL mode
     * (nsboot).
     */
    inline uint8_t get_FLASH_DEVINFO_CS1_GPIO() volatile
    {
        return FLASH_DEVINFO & 0b111111u;
    }

    /**
     * Get FLASH_DEVINFO's D8H_ERASE_SUPPORTED bit.
     *
     * If true, all attached devices are assumed to support (or ignore, in the
     * case of PSRAM) a block erase command with a command prefix of D8h, an
     * erase size of 64 kiB, and a 24-bit address. Almost all 25-series flash
     * devices support this command.
     *
     *                             If set, the bootrom will use the D8h erase
     * command where it is able, to accelerate bulk erase operations. This
     * makes flash programming faster.
     *
     *                             When BOOT_FLAGS0_FLASH_DEVINFO_ENABLE is not
     * set, this field defaults to false.
     */
    inline bool get_FLASH_DEVINFO_D8H_ERASE_SUPPORTED() volatile
    {
        return FLASH_DEVINFO & (1u << 7u);
    }

    /**
     * Get FLASH_DEVINFO's CS0_SIZE field.
     *
     * The size of the flash/PSRAM device on chip select 0 (addressable at
     * 0x10000000 through 0x10ffffff).
     *
     *                             A value of zero is decoded as a size of zero
     * (no device). Nonzero values are decoded as 4kiB << CS0_SIZE. For
     * example, four megabytes is encoded with a CS0_SIZE value of 10, and 16
     * megabytes is encoded with a CS0_SIZE value of 12.
     *
     *                             When BOOT_FLAGS0_FLASH_DEVINFO_ENABLE is not
     * set, a default of 12 (16 MiB) is used.
     */
    inline OTP_DATA_RAW_FLASH_DEVINFO_CS0_SIZE
    get_FLASH_DEVINFO_CS0_SIZE() volatile
    {
        return OTP_DATA_RAW_FLASH_DEVINFO_CS0_SIZE((FLASH_DEVINFO >> 8u) &
                                                   0xfu);
    }

    /**
     * Get FLASH_DEVINFO's CS1_SIZE field.
     *
     * The size of the flash/PSRAM device on chip select 1 (addressable at
     * 0x11000000 through 0x11ffffff).
     *
     *                             A value of zero is decoded as a size of zero
     * (no device). Nonzero values are decoded as 4kiB << CS1_SIZE. For
     * example, four megabytes is encoded with a CS1_SIZE value of 10, and 16
     * megabytes is encoded with a CS1_SIZE value of 12.
     *
     *                             When BOOT_FLAGS0_FLASH_DEVINFO_ENABLE is not
     * set, a default of zero is used.
     */
    inline OTP_DATA_RAW_FLASH_DEVINFO_CS1_SIZE
    get_FLASH_DEVINFO_CS1_SIZE() volatile
    {
        return OTP_DATA_RAW_FLASH_DEVINFO_CS1_SIZE((FLASH_DEVINFO >> 12u) &
                                                   0xfu);
    }

    /**
     * Get all of FLASH_DEVINFO's bit fields.
     *
     * (read-only) Stores information about external flash device(s). (ECC)
     *
     *                     Assumed to be valid if
     * BOOT_FLAGS0_FLASH_DEVINFO_ENABLE is set.
     */
    inline void get_FLASH_DEVINFO(
        uint8_t &CS1_GPIO, bool &D8H_ERASE_SUPPORTED,
        OTP_DATA_RAW_FLASH_DEVINFO_CS0_SIZE &CS0_SIZE,
        OTP_DATA_RAW_FLASH_DEVINFO_CS1_SIZE &CS1_SIZE) volatile
    {
        uint32_t curr = FLASH_DEVINFO;

        CS1_GPIO = curr & 0b111111u;
        D8H_ERASE_SUPPORTED = curr & (1u << 7u);
        CS0_SIZE = OTP_DATA_RAW_FLASH_DEVINFO_CS0_SIZE((curr >> 8u) & 0xfu);
        CS1_SIZE = OTP_DATA_RAW_FLASH_DEVINFO_CS1_SIZE((curr >> 12u) & 0xfu);
    }

